#!/usr/bin/env node
/**
 * Reads Metro City character PNGs and generates a TypeScript module
 * containing base64 data URIs for embedding in the webview bundle.
 */

const fs = require('fs');
const path = require('path');

const MEDIA_DIR = path.join(__dirname, '..', 'media', 'characters');
const OUT_FILE = path.join(__dirname, '..', 'src', 'webview', 'spriteAssets.ts');

const CHARACTER_COUNT = 6;

function generate() {
  const lines = [
    '/** Auto-generated by scripts/generate-sprite-data.js — do not edit */',
    '/** Base64 data URIs for Metro City character sprite sheets */',
    '',
  ];

  const uris = [];

  for (let i = 0; i < CHARACTER_COUNT; i++) {
    const pngPath = path.join(MEDIA_DIR, `char_${i}.png`);
    if (!fs.existsSync(pngPath)) {
      console.error(`Missing: ${pngPath}`);
      process.exit(1);
    }
    const buf = fs.readFileSync(pngPath);
    const b64 = buf.toString('base64');
    uris.push(`  'data:image/png;base64,${b64}'`);
  }

  lines.push(`export const SPRITE_SHEET_URIS: readonly string[] = [`);
  lines.push(uris.join(',\n'));
  lines.push(`];`);
  lines.push('');

  fs.writeFileSync(OUT_FILE, lines.join('\n'));
  console.log(`Generated ${OUT_FILE} (${CHARACTER_COUNT} characters)`);
}

generate();
